#include <stdio.h>
#include <stdlib.h>

void rec(int *l, int *size) {
    while ((*size) > 1 && l[*size - 1] == l[*size - 2]) {
        l[*size - 2] += 1;
        (*size)--;
    }
}

int main() {
    int n;
    scanf("%d", &n);

    int *res = malloc((n + 1) * sizeof(int));
    int size = 1;
    res[0] = 0;

    for (int i = 0; i < n; i++) {
        res[size++] = 1;
        rec(res, &size);
    }

    for (int i = 1; i < size; i++) {
        printf("%d", res[i]);
        if (i < size - 1) {
            printf(" ");
        }
    }
    printf("\n");

    free(res);
    return 0;
}
